// src/pages/admin/AdminDashboard.js
import React, { useEffect, useState } from "react";
import {
  getOverview,
  getUsers,
  getRiders,
  getApprovedCaptains,
  getPendingCaptains,
  getRides,
  approveCaptain,
  rejectCaptain,
} from "../../services/adminApi";
import { useAuth } from "../../contexts/AuthContext";
import {
  AppBar,
  Toolbar,
  Box,
  Typography,
  Button,
  CircularProgress,
  Table,
  TableHead,
  TableBody,
  TableRow,
  TableCell,
  Card,
  CardContent,
  Grid,
  Paper,
  Link,
  Stack,
  Divider,
} from "@mui/material";

// Icons
import PersonIcon from "@mui/icons-material/Person";
import PeopleIcon from "@mui/icons-material/People";
import PendingActionsIcon from "@mui/icons-material/PendingActions";
import LocalTaxiIcon from "@mui/icons-material/LocalTaxi";
import ThumbUpIcon from "@mui/icons-material/ThumbUp";
import ThumbDownIcon from "@mui/icons-material/ThumbDown";

export default function AdminDashboard() {
  const { logout } = useAuth();

  const [overview, setOverview] = useState({
    users: 0,
    riders: 0,
    captains: 0,
    pendingCaptains: 0,
    rides: 0,
  });

  const [activeTab, setActiveTab] = useState("overview");
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  // Fetch overview
  const fetchOverview = async () => {
    try {
      const res = await getOverview();
      setOverview(res.data.data);
    } catch (err) {
      console.error(err);
      setError("Failed to load overview");
    }
  };

  // Fetch table data
  const fetchData = async (type) => {
    setActiveTab(type);
    setLoading(true);
    setError("");
    try {
      let res;
      switch (type) {
        case "users":
          res = await getUsers();
          break;
        case "riders":
          res = await getRiders();
          break;
        case "captains":
          res = await getApprovedCaptains();
          break;
        case "pending":
          res = await getPendingCaptains();
          break;
        case "rides":
          res = await getRides();
          break;
        default:
          res = { data: { data: [] } };
      }
      setData(res?.data?.data || []);
    } catch (err) {
      console.error(err);
      setError("Failed to fetch data");
      setData([]);
    } finally {
      setLoading(false);
    }
  };

  // Approve captain
  const handleApprove = async (id) => {
    try {
      await approveCaptain(id);
      fetchData("pending");
      fetchOverview();
    } catch (err) {
      console.error(err);
      setError("Failed to approve captain");
    }
  };

  // Reject captain
  const handleReject = async (id) => {
    try {
      await rejectCaptain(id);
      fetchData("pending");
      fetchOverview();
    } catch (err) {
      console.error(err);
      setError("Failed to reject captain");
    }
  };

  useEffect(() => {
    fetchOverview();
  }, []);

  // Dashboard cards
  const cards = [
    { label: "Users", value: overview.users, icon: <PersonIcon fontSize="large" />, type: "users" },
    { label: "Riders", value: overview.riders, icon: <PeopleIcon fontSize="large" />, type: "riders" },
    { label: "Approved Captains", value: overview.captains, icon: <PeopleIcon fontSize="large" />, type: "captains" },
    { label: "Pending Captains", value: overview.pendingCaptains, icon: <PendingActionsIcon fontSize="large" />, type: "pending" },
    { label: "Rides", value: overview.rides, icon: <LocalTaxiIcon fontSize="large" />, type: "rides" },
  ];

  return (
    <Box sx={{ minHeight: "100vh", bgcolor: "#f5f5f5" }}>
      {/* Header */}
      <AppBar position="static" sx={{ bgcolor: "primary.main" }}>
        <Toolbar sx={{ display: "flex", justifyContent: "space-between" }}>
          <Typography variant="h5" fontWeight="bold">
            Admin Dashboard
          </Typography>
          <Button variant="contained" color="error" onClick={logout}>
            Logout
          </Button>
        </Toolbar>
      </AppBar>

      <Box px={3} py={4}>
        {/* Overview cards */}
        <Grid container spacing={3} mb={4}>
          {cards.map((card) => (
            <Grid item xs={12} sm={6} md={4} lg={2.4} key={card.label}>
              <Card
                onClick={() => fetchData(card.type)}
                sx={{
                  textAlign: "center",
                  cursor: "pointer",
                  borderRadius: 3,
                  boxShadow: 3,
                  transition: "0.3s",
                  "&:hover": { boxShadow: 6, transform: "translateY(-4px)" },
                  p: 2,
                }}
              >
                <Box color="primary.main">{card.icon}</Box>
                <Typography variant="subtitle1" fontWeight="bold" mt={1}>
                  {card.label}
                </Typography>
                <Typography variant="h5" fontWeight="bold" color="text.primary">
                  {card.value}
                </Typography>
              </Card>
            </Grid>
          ))}
        </Grid>

        <Divider sx={{ mb: 4 }} />

        {/* Loading / Error */}
        {loading && (
          <Box display="flex" justifyContent="center" mt={4}>
            <CircularProgress />
          </Box>
        )}
        {error && (
          <Typography color="error" textAlign="center" mt={2}>
            {error}
          </Typography>
        )}

        {/* Data Table */}
        {!loading && data.length > 0 && (
          <Paper sx={{ p: 3, borderRadius: 3, boxShadow: 3 }}>
            <Typography variant="h6" mb={2} fontWeight="bold">
              {activeTab.charAt(0).toUpperCase() + activeTab.slice(1)} Details
            </Typography>
            <Table>
              <TableHead>
                <TableRow>
                  <TableCell>Name</TableCell>
                  <TableCell>Email</TableCell>
                  <TableCell>Mobile</TableCell>
                  <TableCell>Role</TableCell>
                  {(activeTab === "captains" || activeTab === "pending") && <TableCell>Documents</TableCell>}
                  {activeTab === "pending" && <TableCell align="center">Actions</TableCell>}
                  {activeTab === "rides" && (
                    <>
                      <TableCell>Rider</TableCell>
                      <TableCell>Captain</TableCell>
                      <TableCell>Pickup</TableCell>
                      <TableCell>Drop</TableCell>
                      <TableCell>Status</TableCell>
                    </>
                  )}
                </TableRow>
              </TableHead>
              <TableBody>
                {data.map((item) => (
                  <TableRow key={item._id}>
                    <TableCell>{item.fullName || "-"}</TableCell>
                    <TableCell>{item.email || "-"}</TableCell>
                    <TableCell>{item.mobile || "-"}</TableCell>
                    <TableCell>{item.role || "-"}</TableCell>

                    {(activeTab === "captains" || activeTab === "pending") && (
                      <TableCell>
                        {item.documents?.length > 0 ? (
                          item.documents.map((doc, idx) => (
                            <Box key={idx}>
                              <Link href={doc.url} target="_blank" rel="noopener">
                                {doc.name || `Document ${idx + 1}`}
                              </Link>
                            </Box>
                          ))
                        ) : (
                          "-"
                        )}
                      </TableCell>
                    )}

                    {activeTab === "pending" && (
                      <TableCell align="center">
                        <Stack direction="row" spacing={1} justifyContent="center">
                          <Button
                            size="small"
                            color="success"
                            variant="outlined"
                            startIcon={<ThumbUpIcon />}
                            onClick={() => handleApprove(item._id)}
                          >
                            Approve
                          </Button>
                          <Button
                            size="small"
                            color="error"
                            variant="outlined"
                            startIcon={<ThumbDownIcon />}
                            onClick={() => handleReject(item._id)}
                          >
                            Reject
                          </Button>
                        </Stack>
                      </TableCell>
                    )}

                    {activeTab === "rides" && (
                      <>
                        <TableCell>{item.riderId?.fullName || "-"}</TableCell>
                        <TableCell>{item.captainId?.fullName || "-"}</TableCell>
                        <TableCell>{item.pickup || "-"}</TableCell>
                        <TableCell>{item.drop || "-"}</TableCell>
                        <TableCell>{item.status || "-"}</TableCell>
                      </>
                    )}
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </Paper>
        )}

        {/* No Data */}
        {!loading && data.length === 0 && activeTab !== "overview" && (
          <Typography textAlign="center" mt={3}>
            No data found
          </Typography>
        )}
      </Box>
    </Box>
  );
}
